"use client";

import { useLocale, useTranslations } from "next-intl";
import { useState } from "react";
import { Clock, Mail, MapPin, Phone, ArrowUpRight } from "lucide-react";
import { siteConfig } from "@/lib/config";

const FORM_SUBJECT = "Website contact — inquiry";

const HERO_IMAGE = "data:image/jpeg;base64,";

export default function PremiumContact() {
  const t = useTranslations("ContactPage");
  const locale = useLocale();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [done, setDone] = useState(false);

  const phoneTel = `tel:${siteConfig.contact.phone.replace(/\s/g, "")}`;
  const mailto = `mailto:${siteConfig.contact.email}`;

  async function onSubmit(e: React.FormEvent<HTMLFormElement>) {
    e.preventDefault();
    setLoading(true);
    setError(null);
    const form = e.currentTarget;
    const data = {
      name: (form.elements.namedItem("name") as HTMLInputElement).value,
      email: (form.elements.namedItem("email") as HTMLInputElement).value,
      phone: "",
      company: (form.elements.namedItem("company") as HTMLInputElement).value,
      subject: FORM_SUBJECT,
      message: (form.elements.namedItem("message") as HTMLTextAreaElement).value,
      locale,
    };

    try {
      const res = await fetch("/api/contact", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      });
      if (!res.ok) {
        const json = await res.json().catch(() => ({}));
        throw new Error((json as { error?: string }).error || t("errorGeneric"));
      }
      setDone(true);
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : t("errorGeneric"));
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="min-h-screen bg-white font-sans text-neutral-900 antialiased">
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;1,300;1,400;1,500&family=DM+Sans:wght@300;400;500;600&display=swap');

        .pc-root { font-family: 'DM Sans', sans-serif; }

        /* ── HERO ── */
        .pc-hero {
          position: relative;
          min-height: min(82vh, 920px);
          width: 100%;
          overflow: hidden;
          display: flex;
          flex-direction: column;
          justify-content: flex-end;
        }

        .pc-hero-img {
          position: absolute;
          inset: 0;
          width: 100%;
          height: 100%;
          object-fit: cover;
          object-position: center;
          transform: scale(1.04);
          animation: pc-breathe 22s ease-in-out infinite alternate;
        }
        @keyframes pc-breathe {
          from { transform: scale(1.04); }
          to   { transform: scale(1.09); }
        }

        /* Layered overlays — preserve the monumental depth */
        .pc-ov-top {
          position: absolute; inset: 0;
          background: linear-gradient(to bottom,
            rgba(244,241,234,0.78) 0%,
            rgba(255,255,255,0.45) 35%,
            rgba(255,255,255,0) 55%,
            rgba(244,241,234,0.88) 80%,
            #FFFFFF 100%
          );
          z-index: 1;
        }
        .pc-ov-side {
          position: absolute; inset: 0;
          background: linear-gradient(to right,
            rgba(255,255,255,0.96) 0%,
            rgba(255,255,255,0.55) 45%,
            rgba(255,255,255,0) 100%
          );
          z-index: 2;
        }
        /* Subtle center light — matches the horizon glow in the photo */
        .pc-ov-glow {
          position: absolute; inset: 0;
          background: radial-gradient(ellipse 60% 40% at 50% 48%,
            rgba(200,168,90,0.06) 0%,
            transparent 70%
          );
          z-index: 3;
        }

        .pc-hero-content {
          position: relative;
          z-index: 10;
          max-width: 1280px;
          margin: 0 auto;
          width: 100%;
          padding: 7.75rem 2rem 5rem;
        }
        @media (min-width: 640px)  { .pc-hero-content { padding: 8.75rem 3rem 5.5rem; } }
        @media (min-width: 1024px) { .pc-hero-content { padding: 9.75rem 4rem 6rem; } }

        .pc-eyebrow {
          display: inline-flex;
          align-items: center;
          gap: 0.7rem;
          margin-bottom: 1.75rem;
          opacity: 0;
          animation: pc-rise 0.9s 0.1s cubic-bezier(0.16,1,0.3,1) forwards;
        }
        .pc-eyebrow-line {
          width: 28px; height: 1px;
          background: rgba(200,168,90,0.4);
        }
        .pc-eyebrow-text {
          font-size: 0.64rem;
          font-weight: 500;
          letter-spacing: 0.32em;
          text-transform: uppercase;
          color: rgba(200,168,90,0.55);
        }

        .pc-heading {
          font-family: 'Cormorant Garamond', serif;
          font-weight: 300;
          font-size: clamp(3.2rem, 7.5vw, 7rem);
          line-height: 0.9;
          letter-spacing: -0.025em;
          color: rgba(15,23,41,0.88);
          opacity: 0;
          animation: pc-rise 1s 0.2s cubic-bezier(0.16,1,0.3,1) forwards;
        }
        .pc-heading em {
          display: block;
          font-style: italic;
          font-weight: 400;
          color: #0F1729;
          margin-top: 0.06em;
        }

        .pc-sub {
          margin-top: 1.75rem;
          max-width: 460px;
          font-size: clamp(0.85rem, 1.4vw, 1rem);
          font-weight: 300;
          line-height: 1.8;
          color: rgba(200,168,90,0.65);
          opacity: 0;
          animation: pc-rise 1s 0.35s cubic-bezier(0.16,1,0.3,1) forwards;
        }

        /* Vertical rule + scroll hint bottom-right */
        .pc-scroll-hint {
          position: absolute;
          bottom: 2.5rem;
          right: 2rem;
          z-index: 10;
          display: flex;
          flex-direction: column;
          align-items: center;
          gap: 0.6rem;
          opacity: 0;
          animation: pc-rise 1s 0.6s ease forwards;
        }
        @media (min-width: 640px) { .pc-scroll-hint { right: 3rem; } }
        @media (min-width: 1024px) { .pc-scroll-hint { right: 4rem; } }
        .pc-scroll-line {
          width: 1px;
          height: 52px;
          background: linear-gradient(to bottom, transparent, rgba(200,168,90,0.4));
          animation: pc-scrollpulse 2.4s ease-in-out infinite;
        }
        @keyframes pc-scrollpulse {
          0%,100% { opacity: 0.3; }
          50%      { opacity: 0.9; }
        }
        .pc-scroll-label {
          font-size: 0.58rem;
          letter-spacing: 0.22em;
          text-transform: uppercase;
          color: rgba(200,168,90,0.4);
          writing-mode: vertical-rl;
        }

        @keyframes pc-rise {
          from { opacity: 0; transform: translateY(18px); }
          to   { opacity: 1; transform: translateY(0); }
        }
      `}</style>

      {/* ── HERO ── */}
      <section className="pc-root pc-hero">
        <img
          src={HERO_IMAGE}
          alt=""
          className="pc-hero-img"
        />
        <div className="pc-ov-top"  aria-hidden />
        <div className="pc-ov-side" aria-hidden />
        <div className="pc-ov-glow" aria-hidden />

        <div className="pc-hero-content">
          <div className="pc-eyebrow">
            <div className="pc-eyebrow-line" />
            <span className="pc-eyebrow-text">{t("eyebrow")}</span>
          </div>

          <h1 className="pc-heading">
            {t("heroTitle1")}
            <em>{t("heroTitle2")}</em>
          </h1>

          <p className="pc-sub">{t("heroSubtitle")}</p>
        </div>

        {/* Scroll hint */}
        <div className="pc-scroll-hint" aria-hidden>
          <div className="pc-scroll-line" />
          <span className="pc-scroll-label">{t("scrollHint")}</span>
        </div>
      </section>

      {/* ── MAIN ── */}
      <section className="border-t border-[rgba(15,23,41,0.08)] bg-[#FBF8F2] px-6 py-20 sm:px-8 lg:px-10 lg:py-28">
        <div className="mx-auto grid max-w-7xl gap-16 lg:grid-cols-2 lg:gap-24">

          {/* Info */}
          <div className="flex flex-col gap-12">
            <div>
              <h2 className="text-2xl font-medium tracking-tight text-[#0F1729] sm:text-3xl">
                {t("getInTouch")}
              </h2>
              <p className="mt-5 max-w-md text-sm font-light leading-relaxed text-slate-600">
                {t("intro")}
              </p>
            </div>

            <div className="h-px w-full max-w-sm bg-gradient-to-r from-[rgba(200,168,90,0.55)] to-transparent" />

            <ul className="flex flex-col gap-10">
              <li className="flex gap-4">
                <span className="mt-0.5 flex h-10 w-10 shrink-0 items-center justify-center rounded-full border border-[rgba(200,168,90,0.32)] bg-[rgba(200,168,90,0.08)] text-[#B09347]">
                  <Phone className="h-4 w-4" strokeWidth={1.5} />
                </span>
                <div>
                  <p className="text-[0.65rem] font-semibold uppercase tracking-[0.2em] text-slate-500">
                    {t("labelPhone")}
                  </p>
                  <a href={phoneTel} className="mt-1 block text-sm font-medium text-[#0F1729] transition hover:text-[#B09347]">
                    {siteConfig.contact.phone}
                  </a>
                </div>
              </li>
              <li className="flex gap-4">
                <span className="mt-0.5 flex h-10 w-10 shrink-0 items-center justify-center rounded-full border border-[rgba(200,168,90,0.32)] bg-[rgba(200,168,90,0.08)] text-[#B09347]">
                  <Mail className="h-4 w-4" strokeWidth={1.5} />
                </span>
                <div>
                  <p className="text-[0.65rem] font-semibold uppercase tracking-[0.2em] text-slate-500">
                    {t("labelEmail")}
                  </p>
                  <a href={mailto} className="mt-1 block text-sm font-medium text-[#0F1729] underline-offset-4 transition hover:text-[#B09347] hover:underline">
                    {siteConfig.contact.email}
                  </a>
                </div>
              </li>
              <li className="flex gap-4">
                <span className="mt-0.5 flex h-10 w-10 shrink-0 items-center justify-center rounded-full border border-[rgba(200,168,90,0.32)] bg-[rgba(200,168,90,0.08)] text-[#B09347]">
                  <MapPin className="h-4 w-4" strokeWidth={1.5} />
                </span>
                <div>
                  <p className="text-[0.65rem] font-semibold uppercase tracking-[0.2em] text-slate-500">
                    {t("labelAddress")}
                  </p>
                  <p className="mt-1 max-w-sm text-sm font-light leading-relaxed text-slate-700">
                    {siteConfig.legalName}<br />
                    {siteConfig.contact.address.street}<br />
                    {siteConfig.contact.address.city}, {siteConfig.contact.address.country}
                  </p>
                </div>
              </li>
              <li className="flex gap-4">
                <span className="mt-0.5 flex h-10 w-10 shrink-0 items-center justify-center rounded-full border border-[rgba(200,168,90,0.32)] bg-[rgba(200,168,90,0.08)] text-[#B09347]">
                  <Clock className="h-4 w-4" strokeWidth={1.5} />
                </span>
                <div>
                  <p className="text-[0.65rem] font-semibold uppercase tracking-[0.2em] text-slate-500">
                    {t("labelHours")}
                  </p>
                  <p className="mt-1 text-sm font-light text-slate-700">{t("hoursValue")}</p>
                </div>
              </li>
            </ul>
          </div>

          {/* Form */}
          <div>
            {done ? (
              <div className="rounded-2xl border border-[rgba(15,23,41,0.10)] bg-white p-10 shadow-[0_24px_60px_rgba(15,23,41,0.08)]">
                <h3 className="text-xl font-medium text-[#0F1729]">{t("successTitle")}</h3>
                <p className="mt-3 text-sm font-light leading-relaxed text-slate-600">{t("successBody")}</p>
                <button
                  type="button"
                  onClick={() => setDone(false)}
                  className="mt-8 text-[0.7rem] font-semibold uppercase tracking-[0.15em] text-slate-500 transition hover:text-[#B09347]"
                >
                  {t("sendAnother")}
                </button>
              </div>
            ) : (
              <form
                onSubmit={onSubmit}
                className="rounded-2xl border border-[rgba(15,23,41,0.10)] bg-white p-8 shadow-[0_24px_60px_rgba(15,23,41,0.08)] sm:p-10"
              >
                <div className="flex flex-col gap-6">
                  <div>
                    <label htmlFor="pc-name" className="mb-2 block text-[0.65rem] font-semibold uppercase tracking-[0.18em] text-slate-500">
                      {t("fieldName")}
                    </label>
                    <input
                      id="pc-name" name="name" required autoComplete="name"
                      className="w-full rounded-lg border border-[rgba(15,23,41,0.12)] bg-white px-4 py-3.5 text-sm font-normal text-[#0F1729] placeholder:text-slate-400 outline-none transition hover:border-[rgba(200,168,90,0.55)] focus:border-[#C8A85A] focus:ring-2 focus:ring-[rgba(200,168,90,0.18)]"
                      placeholder={t("phName")}
                    />
                  </div>
                  <div>
                    <label htmlFor="pc-email" className="mb-2 block text-[0.65rem] font-semibold uppercase tracking-[0.18em] text-slate-500">
                      {t("fieldEmail")}
                    </label>
                    <input
                      id="pc-email" name="email" type="email" required autoComplete="email"
                      className="w-full rounded-lg border border-[rgba(15,23,41,0.12)] bg-white px-4 py-3.5 text-sm font-normal text-[#0F1729] placeholder:text-slate-400 outline-none transition hover:border-[rgba(200,168,90,0.55)] focus:border-[#C8A85A] focus:ring-2 focus:ring-[rgba(200,168,90,0.18)]"
                      placeholder={t("phEmail")}
                    />
                  </div>
                  <div>
                    <label htmlFor="pc-company" className="mb-2 block text-[0.65rem] font-semibold uppercase tracking-[0.18em] text-slate-500">
                      {t("fieldCompany")}
                    </label>
                    <input
                      id="pc-company" name="company" autoComplete="organization"
                      className="w-full rounded-lg border border-[rgba(15,23,41,0.12)] bg-white px-4 py-3.5 text-sm font-normal text-[#0F1729] placeholder:text-slate-400 outline-none transition hover:border-[rgba(200,168,90,0.55)] focus:border-[#C8A85A] focus:ring-2 focus:ring-[rgba(200,168,90,0.18)]"
                      placeholder={t("phCompany")}
                    />
                  </div>
                  <div>
                    <label htmlFor="pc-message" className="mb-2 block text-[0.65rem] font-semibold uppercase tracking-[0.18em] text-slate-500">
                      {t("fieldMessage")}
                    </label>
                    <textarea
                      id="pc-message" name="message" required rows={5}
                      className="w-full resize-y rounded-lg border border-[rgba(15,23,41,0.12)] bg-white px-4 py-3.5 text-sm font-normal text-[#0F1729] placeholder:text-slate-400 outline-none transition hover:border-[rgba(200,168,90,0.55)] focus:border-[#C8A85A] focus:ring-2 focus:ring-[rgba(200,168,90,0.18)]"
                      placeholder={t("phMessage")}
                    />
                  </div>
                </div>

                {error && (
                  <p className="mt-4 text-sm font-light text-red-600" role="alert">{error}</p>
                )}

                <button
                  type="submit"
                  disabled={loading}
                  className="mt-8 flex w-full items-center justify-center gap-2 rounded-full border border-[#C8A85A] bg-[#C8A85A] py-4 text-[0.7rem] font-semibold uppercase tracking-[0.2em] text-[#0F1729] transition hover:bg-[#B09347] hover:border-[#B09347] disabled:cursor-not-allowed disabled:opacity-60"
                >
                  {loading ? t("sending") : t("submit")}
                  {!loading && <ArrowUpRight className="h-4 w-4" strokeWidth={2} />}
                </button>
              </form>
            )}
          </div>
        </div>
      </section>
    </div>
  );
}
